changeSet.sql:
-- Fiscal Years and Periods CREATE TABLE IF NOT EXISTS fiscal_years ( id Integer not null, created_by character varying(255) , created_date timestamp(6) without time zone NOT NULL, last_modified_by character varying(255) , last_modified_date timestamp(6) without time zone, deleted_by character varying(255) , deleted_date timestamp(6) without time zone, is_delete boolean DEFAULT false, serial_id VARCHAR(50) UNIQUE NOT NULL, name VARCHAR(50) NOT NULL, start_date DATE NOT NULL, end_date DATE NOT NULL, is_closed BOOLEAN DEFAULT FALSE, account_id BIGINT not null, CONSTRAINT fiscal_years_p_key PRIMARY KEY (id) );
CREATE SEQUENCE IF NOT EXISTS fiscal_period_seq INCREMENT 1 START 1 NO MINVALUE NO MAXVALUE CACHE 1 OWNED BY fiscal_years.id;
CREATE TABLE IF NOT EXISTS fiscal_periods ( id Integer not null, created_by character varying(255) , created_date timestamp(6) without time zone NOT NULL, last_modified_by character varying(255) , last_modified_date timestamp(6) without time zone, deleted_by character varying(255) , deleted_date timestamp(6) without time zone, is_delete boolean DEFAULT false, serial_id VARCHAR(50) UNIQUE NOT NULL, fiscal_year_id Integer REFERENCES fiscal_years(id), name VARCHAR(50) NOT NULL, start_date DATE NOT NULL, end_date DATE NOT NULL, is_closed BOOLEAN DEFAULT FALSE, CONSTRAINT fiscal_periods_p_key PRIMARY KEY (id) );
CREATE SEQUENCE IF NOT EXISTS fiscal_year_seq INCREMENT 1 START 1 NO MINVALUE NO MAXVALUE CACHE 1 OWNED BY fiscal_periods.id;
